@startuml
skinparam classDiagram labelStyle fontname "Helvetica"
skinparam classDiagram classStyle fontname "Helvetica"
skinparam classDiagram style classStyle fillColor "#f0f0f0"
skinparam classDiagram style interfaceStyle fillColor "#d0d0f0"

interface ILogCollector {
    collect()
}

class FtpLogFileDownloader {
    +download()
}

class SockerLogReader {
    +read()
}

class DbTableLogGateway {
    +query()
}

class LogCollector {
    +collect()
}

LogCollector <|-- FtpLogFileDownloader
LogCollector <|-- SockerLogReader
LogCollector <|-- DbTableLogGateway

@enduml
